arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);

// Register the ML.NET prediction engine pool (thread-safe for web apps)
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
var modelPath = Path.Combine(AppContext.BaseDirectory, "ChurnModel.zip");

TrainAndSaveModel(mlContext, dataPath, modelPath);

builder.Services.AddPredictionEnginePool<ChurnInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST to /predict");

app.MapPost("/predict", (ChurnInput input, PredictionEnginePool<ChurnInput, ChurnPrediction> pool) =>
{
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability,
        Score = prediction.Score,
    });
});

app.Run();

static void TrainAndSaveModel(MLContext mlContext, string dataPath, string modelPath)
{
    var data = mlContext.Data.LoadFromTextFile<ChurnInput>(
        dataPath, hasHeader: true, separatorChar: ',');

    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

    // Map the string label ("Yes"/"No") to a boolean, one-hot encode Region
    var pipeline = mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(ChurnInput.Churned))
        .Append(mlContext.Transforms.Categorical
            .OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region)))
        .Append(mlContext.Transforms.Concatenate("Features",
            nameof(ChurnInput.Age),
            nameof(ChurnInput.Income),
            "RegionEncoded",
            nameof(ChurnInput.PurchaseHistory)))
        .Append(mlContext.Transforms.NormalizeMinMax("Features"))
        .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression())
        .Append(mlContext.Transforms.Conversion
            .MapKeyToValue("PredictedLabel"));

    var model = pipeline.Fit(split.TrainSet);

    // Evaluate on the held-out test set
    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions);
    Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");
    Console.WriteLine($"AUC:      {metrics.AreaUnderRocCurve:F4}");
    Console.WriteLine($"F1:       {metrics.F1Score:F4}");

    mlContext.Model.Save(model, data.Schema, modelPath);
    Console.WriteLine($"Model saved to {modelPath}");
}

// --- Data models ---

public class ChurnInput
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = string.Empty;
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedLabel { get; set; } = string.Empty;
    public float Probability { get; set; }
    public float Score { get; set; }
}

